    engineVersion,
    activeProvider,
    typedSql,
    target,
    generatedFileExtension,
    importFileExtension,
    moduleFormat,
    tsNoCheckPreamble,
    compilerBuild,
  } = options

  const { runtimeBase, outputDir } = await getGenerationDirs(options)

  const { prismaClientDmmf, fileMap } = buildClient({
    datamodel,
