## Step 8: Create `packages/rest-client-generator/src/generate-client.ts`

This is the main orchestrator. It reads the DMMF, calls the per-model and client generators, and writes files.

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { generateClientFile } from './client-file-generator'
import { generateModelFile } from './model-file-generator'

interface FileMap {
  [name: string]: string | FileMap
}

export async function generateClient(dmmf: DMMF.Document, outputDir: string): Promise<void> {
  const models = dmmf.datamodel.models

  const modelFiles: FileMap = {}
  for (const model of models) {
    modelFiles[`${model.name}.ts`] = generateModelFile(model)
  }

  const enumsFile = generateEnumsFile(dmmf.datamodel.enums)

  const fileMap: FileMap = {
    models: modelFiles,
    'client.ts': generateClientFile(models),
    'index.ts': generateIndexFile(models, dmmf.datamodel.enums),
    ...(enumsFile ? { 'enums.ts': enumsFile } : {}),
  }

  await writeFileMap(outputDir, fileMap)
}

function generateEnumsFile(enums: readonly DMMF.DatamodelEnum[]): string | null {
  if (enums.length === 0) return null

  return enums
    .map((e) => {
      const values = e.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
      return `export enum ${e.name} {\n${values}\n}`
    })
    .join('\n\n') + '\n'
}

function generateIndexFile(
  models: readonly DMMF.Model[],
  enums: readonly DMMF.DatamodelEnum[],
): string {
  const lines: string[] = []

  lines.push(`export { RestClient } from './client'`)
  lines.push(`export type { RestClientOptions } from './client'`)

  if (enums.length > 0) {
    lines.push(`export { ${enums.map((e) => e.name).join(', ')} } from './enums'`)
  }

  for (const model of models) {
    lines.push(
      `export type { ${model.name}, ${model.name}WhereUniqueInput, ${model.name}CreateInput, ${model.name}UpdateInput } from './models/${model.name}'`,
    )
  }

  return lines.join('\n') + '\n'
}

async function writeFileMap(outputDir: string, fileMap: FileMap): Promise<void> {
  await Promise.all(
    Object.entries(fileMap).map(async ([fileName, content]) => {
      const absolutePath = path.join(outputDir, fileName)
      await fs.rm(absolutePath, { recursive: true, force: true })
      if (typeof content === 'string') {
        await fs.mkdir(path.dirname(absolutePath), { recursive: true })
        await fs.writeFile(absolutePath, content)
      } else {
        await fs.mkdir(absolutePath, { recursive: true })
        await writeFileMap(absolutePath, content as FileMap)
      }
    }),
  )
}
```

Key DMMF usage:
- `dmmf.datamodel.models` — the array of `DMMF.Model` objects.
- `dmmf.datamodel.enums` — the array of `DMMF.DatamodelEnum` objects. Note the type is `DatamodelEnum`, not the raw `Enum` — `DatamodelEnum` has `values: EnumValue[]` where each `EnumValue` has a `name: string` property.
- `dmmf.datamodel.types` — composite/embedded types — not handled in this generator (out of scope for a basic REST client).

The `writeFileMap` differs slightly from `client-generator-ts`'s version: it adds `fs.mkdir` before `writeFile` to create intermediate directories for model files (since `models/User.ts` requires `models/` to exist).

Enum generation produces TypeScript `enum` declarations (not `const enum` or type unions) because string enums are easy to serialize/deserialize over HTTP and match Prisma's own convention.

