## Step 7: Create `packages/rest-client-generator/src/client-file-generator.ts`

This generates `client.ts` with the `RestClient` class.

```typescript
import type * as DMMF from '@prisma/dmmf'

export function generateClientFile(models: readonly DMMF.Model[]): string {
  const imports = generateModelImports(models)
  const classBody = generateRestClientClass(models)
  return `${imports}\n\n${classBody}\n`
}

function modelAccessorName(modelName: string): string {
  return modelName.charAt(0).toLowerCase() + modelName.slice(1)
}

function generateModelImports(models: readonly DMMF.Model[]): string {
  return models
    .map(
      (m) =>
        `import type { ${m.name}, ${m.name}WhereUniqueInput, ${m.name}CreateInput, ${m.name}UpdateInput } from './models/${m.name}'`,
    )
    .join('\n')
}

function generateRestClientClass(models: readonly DMMF.Model[]): string {
  const modelProperties = models
    .map((m) => generateModelProperty(m))
    .join('\n\n')

  return `export interface RestClientOptions {
  baseUrl: string
  headers?: Record<string, string>
}

export class RestClient {
  #baseUrl: string
  #headers: Record<string, string>

  constructor(options: RestClientOptions) {
    this.#baseUrl = options.baseUrl.replace(/\\/$/, '')
    this.#headers = options.headers ?? {}
  }

${modelProperties}

  #fetch<T>(path: string, init?: RequestInit): Promise<T> {
    return fetch(\`\${this.#baseUrl}\${path}\`, {
      ...init,
      headers: {
        'Content-Type': 'application/json',
        ...this.#headers,
        ...init?.headers,
      },
    }).then((res) => {
      if (!res.ok) {
        return res.text().then((body) => {
          throw new Error(\`HTTP \${res.status}: \${body}\`)
        })
      }
      return res.json() as Promise<T>
    })
  }
}`
}

function generateModelProperty(model: DMMF.Model): string {
  const name = modelAccessorName(model.name)
  const M = model.name

  return `  readonly ${name} = {
    findMany: (params?: { skip?: number; take?: number }): Promise<${M}[]> => {
      const query = params ? \`?\${new URLSearchParams(params as Record<string, string>).toString()}\` : ''
      return this.#fetch<${M}[]>(\`/${name}\${query}\`)
    },
    findUnique: (where: ${M}WhereUniqueInput): Promise<${M} | null> =>
      this.#fetch<${M} | null>(\`/${name}/\${JSON.stringify(where)}\`),
    create: (data: ${M}CreateInput): Promise<${M}> =>
      this.#fetch<${M}>(\`/${name}\`, {
        method: 'POST',
        body: JSON.stringify(data),
      }),
    update: (where: ${M}WhereUniqueInput, data: ${M}UpdateInput): Promise<${M}> =>
      this.#fetch<${M}>(\`/${name}/\${JSON.stringify(where)}\`, {
        method: 'PATCH',
        body: JSON.stringify(data),
      }),
    delete: (where: ${M}WhereUniqueInput): Promise<${M}> =>
      this.#fetch<${M}>(\`/${name}/\${JSON.stringify(where)}\`, {
        method: 'DELETE',
      }),
  }`
}
```

Notes:
- `#baseUrl` and `#headers` use native private fields (not TypeScript `private`) per the monorepo convention.
- `modelAccessorName` lowercases the first letter to convert `User` → `user` accessor.
- The `#fetch` helper handles the JSON decode and HTTP error path.
- The URL routing pattern uses `JSON.stringify(where)` to serialize composite keys. This is a simplification; real implementations would parse the unique input into URL path/query segments. The important thing here is the generated types are correct — the routing implementation is secondary to the generation plan.

---

## Step 8: Create `packages/rest-client-generator/src/generate-client.ts`

This is the main orchestrator. It reads the DMMF, calls the per-model and client generators, and writes files.

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { generateClientFile } from './client-file-generator'
import { generateModelFile } from './model-file-generator'

interface FileMap {
  [name: string]: string | FileMap
}

export async function generateClient(dmmf: DMMF.Document, outputDir: string): Promise<void> {
  const models = dmmf.datamodel.models

  const modelFiles: FileMap = {}
  for (const model of models) {
    modelFiles[`${model.name}.ts`] = generateModelFile(model)
  }

  const enumsFile = generateEnumsFile(dmmf.datamodel.enums)

  const fileMap: FileMap = {
    models: modelFiles,
    'client.ts': generateClientFile(models),
    'index.ts': generateIndexFile(models, dmmf.datamodel.enums),
    ...(enumsFile ? { 'enums.ts': enumsFile } : {}),
  }

  await writeFileMap(outputDir, fileMap)
}

function generateEnumsFile(enums: readonly DMMF.DatamodelEnum[]): string | null {
  if (enums.length === 0) return null

  return enums
    .map((e) => {
      const values = e.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
      return `export enum ${e.name} {\n${values}\n}`
    })
    .join('\n\n') + '\n'
}

function generateIndexFile(
  models: readonly DMMF.Model[],
  enums: readonly DMMF.DatamodelEnum[],
): string {
  const lines: string[] = []

  lines.push(`export { RestClient } from './client'`)
  lines.push(`export type { RestClientOptions } from './client'`)

  if (enums.length > 0) {
    lines.push(`export { ${enums.map((e) => e.name).join(', ')} } from './enums'`)
  }

  for (const model of models) {
    lines.push(
      `export type { ${model.name}, ${model.name}WhereUniqueInput, ${model.name}CreateInput, ${model.name}UpdateInput } from './models/${model.name}'`,
    )
  }

  return lines.join('\n') + '\n'
}

async function writeFileMap(outputDir: string, fileMap: FileMap): Promise<void> {
  await Promise.all(
    Object.entries(fileMap).map(async ([fileName, content]) => {
      const absolutePath = path.join(outputDir, fileName)
      await fs.rm(absolutePath, { recursive: true, force: true })
      if (typeof content === 'string') {
        await fs.mkdir(path.dirname(absolutePath), { recursive: true })
        await fs.writeFile(absolutePath, content)
      } else {
        await fs.mkdir(absolutePath, { recursive: true })
        await writeFileMap(absolutePath, content as FileMap)
      }
    }),
  )
}
```

Key DMMF usage:
- `dmmf.datamodel.models` — the array of `DMMF.Model` objects.
- `dmmf.datamodel.enums` — the array of `DMMF.DatamodelEnum` objects. Note the type is `DatamodelEnum`, not the raw `Enum` — `DatamodelEnum` has `values: EnumValue[]` where each `EnumValue` has a `name: string` property.
- `dmmf.datamodel.types` — composite/embedded types — not handled in this generator (out of scope for a basic REST client).

The `writeFileMap` differs slightly from `client-generator-ts`'s version: it adds `fs.mkdir` before `writeFile` to create intermediate directories for model files (since `models/User.ts` requires `models/` to exist).

Enum generation produces TypeScript `enum` declarations (not `const enum` or type unions) because string enums are easy to serialize/deserialize over HTTP and match Prisma's own convention.

---

## Step 9: Create `packages/rest-client-generator/src/generator.ts`

```typescript
import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateClient } from './generate-client'

export const RestClientGenerator: Generator = {
  name: 'rest-client-generator',

  getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      prettyName: 'Prisma REST Client Generator',
      defaultOutput: 'node_modules/.prisma/rest-client',
      requiresEngines: [],
    })
  },

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = options.generator.output?.value ?? 'rest-client'
    await generateClient(options.dmmf, outputDir)
  },
}
```

Notes:
- `options.generator.output` is typed as `EnvValue | null`. The `?.value` null-coalescing chain handles both `null` and `{ value: null }` cases.
- `requiresEngines: []` means the generator does not require any engine binary (schema-engine, etc.) — correct for a pure code generator.
- The `_config` prefix signals the parameter is intentionally unused (satisfies the `Generator` interface contract without a lint warning about unused variables).

