# Plan: `@prisma/rest-client-generator`

## Context

Add a new Prisma generator package to the monorepo that implements the standard Prisma generator protocol (JSON-RPC over stdin/stderr) and, for each model in the schema, emits TypeScript interfaces and a typed `RestClient` class with CRUD methods (`findMany`, `findUnique`, `create`, `update`, `delete`). The package follows the exact same conventions used by `packages/adapter-pg` (the simplest bundled package in the repo) and hooks into the existing build and CI infrastructure.

---

## Files to Create

### `packages/rest-client-generator/package.json`
Mirror `packages/adapter-pg/package.json` exactly, adjusting name/description/directory/dependencies:

```json
{
  "name": "@prisma/rest-client-generator",
  "version": "0.0.0",
  "description": "Prisma generator that produces a typed REST API client from a Prisma schema",
  "main": "dist/index.js",
  "module": "dist/index.mjs",
  "types": "dist/index.d.ts",
  "exports": {
    ".": {
      "require": { "types": "./dist/index.d.ts", "default": "./dist/index.js" },
      "import":  { "types": "./dist/index.d.mts", "default": "./dist/index.mjs" }
    }
  },
  "repository": {
    "type": "git",
    "url": "https://github.com/prisma/prisma.git",
    "directory": "packages/rest-client-generator"
  },
  "license": "Apache-2.0",
  "scripts": {
    "dev": "DEV=true tsx helpers/build.ts",
    "build": "tsx helpers/build.ts",
    "test": "vitest run",
    "prepublishOnly": "pnpm run build"
  },
  "files": ["dist"],
  "sideEffects": false,
  "dependencies": {
    "@prisma/dmmf": "workspace:*",
    "@prisma/generator": "workspace:*",
    "@prisma/generator-helper": "workspace:*"
  },
  "devDependencies": {
    "@types/node": "~20.19.24",
    "typescript": "5.4.5"
  }
}
```

> **Why `@prisma/generator-helper`**: the actual JSON-RPC bootstrap (`generatorHandler`) lives there; `@prisma/generator` provides only the type definitions (`Generator`, `GeneratorOptions`, `GeneratorManifest`, `GeneratorConfig`).

---

### `packages/rest-client-generator/tsconfig.json`
```json
{ "extends": "../../tsconfig.json" }
```

### `packages/rest-client-generator/tsconfig.build.json`
```json
{
  "extends": "../../tsconfig.build.regular.json",
  "compilerOptions": { "outDir": "declaration" },
  "include": ["src"]
}
```

### `packages/rest-client-generator/helpers/build.ts`
```typescript
import { build } from '../../../helpers/compile/build'
import { adapterConfig } from '../../../helpers/compile/configs'

void build(adapterConfig)
```
`adapterConfig` produces two esbuild passes: `src/index.ts → dist/index.js` (CJS, with type declarations) and `→ dist/index.mjs` (ESM). Workspace dependencies (`@prisma/generator-helper`, etc.) are automatically externalised because they appear in `dependencies`.

---

### `packages/rest-client-generator/src/prisma-type-to-ts.ts`

Maps DMMF scalar `Field.type` strings to TypeScript type strings. Enum and relation model names pass through unchanged (they become TypeScript identifiers in the generated code).

```typescript
const SCALAR_TYPE_MAP: Record<string, string> = {
  String:   'string',
  Int:      'number',
  Float:    'number',
  Boolean:  'boolean',
  DateTime: 'Date',
  BigInt:   'bigint',
  Decimal:  'string',   // serialised as string over HTTP
  Bytes:    'Buffer',
  Json:     'unknown',  // safer than any for a typed client
}

/** Maps a Prisma scalar type name to its TypeScript equivalent. */
export function prismaTypeToTs(prismaType: string): string {
  return SCALAR_TYPE_MAP[prismaType] ?? prismaType
}
```

---

### `packages/rest-client-generator/src/model-file-generator.ts`

Generates the content of `models/{ModelName}.ts` for a single DMMF model. Key DMMF field properties used:

| Property | Purpose |
|---|---|
| `field.kind === 'scalar' \|\| 'enum'` | Includes only serialisable fields; excludes `'object'` (relations) and `'unsupported'` |
| `field.isRequired` | Controls `?` in the base interface |
| `field.isList` | Appends `[]` to the type |
| `field.isId` | Excluded from CreateInput/UpdateInput; included in WhereUniqueInput |
| `field.isUnique` | Also included in WhereUniqueInput |
| `field.isReadOnly` | Excluded from CreateInput/UpdateInput (e.g. `@updatedAt` fields) |
| `field.hasDefaultValue` | Makes field optional in CreateInput |

```typescript
import type * as DMMF from '@prisma/dmmf'
import { prismaTypeToTs } from './prisma-type-to-ts'

export function generateModelFile(model: DMMF.Model): string {
  return [
    generateBaseInterface(model),
    generateWhereUniqueInput(model),
    generateCreateInput(model),
    generateUpdateInput(model),
  ].join('\n\n') + '\n'
}

function isSerializable(field: DMMF.Field): boolean {
  return field.kind === 'scalar' || field.kind === 'enum'
}

function fieldType(field: DMMF.Field): string {
  const base = prismaTypeToTs(field.type)
  return field.isList ? `${base}[]` : base
}

function generateBaseInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter(isSerializable)
    .map((f) => `  ${f.name}${f.isRequired ? '' : '?'}: ${fieldType(f)}`)
    .join('\n')
  return `export interface ${model.name} {\n${fields}\n}`
}

function generateWhereUniqueInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => isSerializable(f) && (f.isId || f.isUnique))
    .map((f) => `  ${f.name}?: ${fieldType(f)}`)
    .join('\n')
  return `export interface ${model.name}WhereUniqueInput {\n${fields}\n}`
}

function generateCreateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => isSerializable(f) && !f.isId && !f.isReadOnly)
    .map((f) => {
      const optional = !f.isRequired || f.hasDefaultValue ? '?' : ''
      return `  ${f.name}${optional}: ${fieldType(f)}`
    })
    .join('\n')
  return `export interface ${model.name}CreateInput {\n${fields}\n}`
}

function generateUpdateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => isSerializable(f) && !f.isId && !f.isReadOnly)
    .map((f) => `  ${f.name}?: ${fieldType(f)}`)
    .join('\n')
  return `export interface ${model.name}UpdateInput {\n${fields}\n}`
}
```

---

### `packages/rest-client-generator/src/client-file-generator.ts`

Generates the `client.ts` file containing `RestClientOptions` and `RestClient`. Uses native `#` private fields (monorepo convention). The accessor name is the model name with a lowercased first letter (`User` → `user`).

```typescript
import type * as DMMF from '@prisma/dmmf'

export function generateClientFile(models: readonly DMMF.Model[]): string {
  const imports = models
    .map(
      (m) =>
        `import type { ${m.name}, ${m.name}WhereUniqueInput, ${m.name}CreateInput, ${m.name}UpdateInput } from './models/${m.name}'`,
    )
    .join('\n')

  const modelAccessors = models.map(generateModelAccessor).join('\n\n')

  return `${imports}

export interface RestClientOptions {
  baseUrl: string
  headers?: Record<string, string>
}

export class RestClient {
  #baseUrl: string
  #headers: Record<string, string>

  constructor(options: RestClientOptions) {
    this.#baseUrl = options.baseUrl.replace(/\\/$/, '')
    this.#headers = options.headers ?? {}
  }

${modelAccessors}

  #fetch<T>(path: string, init?: RequestInit): Promise<T> {
    return fetch(\`\${this.#baseUrl}\${path}\`, {
      ...init,
      headers: { 'Content-Type': 'application/json', ...this.#headers, ...init?.headers },
    }).then((res) => {
      if (!res.ok) {
        return res.text().then((body) => { throw new Error(\`HTTP \${res.status}: \${body}\`) })
      }
      return res.json() as Promise<T>
    })
  }
}
`
}

function accessorName(modelName: string): string {
  return modelName.charAt(0).toLowerCase() + modelName.slice(1)
}

function generateModelAccessor(model: DMMF.Model): string {
  const acc = accessorName(model.name)
  const M = model.name
  return `  readonly ${acc} = {
    findMany: (params?: { skip?: number; take?: number }): Promise<${M}[]> => {
      const qs = params ? \`?\${new URLSearchParams(params as Record<string, string>)}\` : ''
      return this.#fetch<${M}[]>(\`/${acc}\${qs}\`)
    },
    findUnique: (where: ${M}WhereUniqueInput): Promise<${M} | null> =>
      this.#fetch<${M} | null>(\`/${acc}/\${encodeURIComponent(JSON.stringify(where))}\`),
    create: (data: ${M}CreateInput): Promise<${M}> =>
      this.#fetch<${M}>(\`/${acc}\`, { method: 'POST', body: JSON.stringify(data) }),
    update: (where: ${M}WhereUniqueInput, data: ${M}UpdateInput): Promise<${M}> =>
      this.#fetch<${M}>(\`/${acc}/\${encodeURIComponent(JSON.stringify(where))}\`, {
        method: 'PATCH',
        body: JSON.stringify(data),
      }),
    delete: (where: ${M}WhereUniqueInput): Promise<${M}> =>
      this.#fetch<${M}>(\`/${acc}/\${encodeURIComponent(JSON.stringify(where))}\`, { method: 'DELETE' }),
  }`
}
```

---

### `packages/rest-client-generator/src/generate-client.ts`

Main orchestrator: reads `dmmf.datamodel`, calls the per-model and client file generators, and writes the `FileMap` to disk. The `writeFileMap` helper is adapted from `packages/client-generator-ts/src/generateClient.ts` with an added `mkdir` for intermediate directories (needed because model files live in a `models/` subdirectory).

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { generateClientFile } from './client-file-generator'
import { generateModelFile } from './model-file-generator'

interface FileMap {
  [name: string]: string | FileMap
}

export async function generateClient(dmmf: DMMF.Document, outputDir: string): Promise<void> {
  const { models, enums } = dmmf.datamodel

  const modelFiles: FileMap = {}
  for (const model of models) {
    modelFiles[`${model.name}.ts`] = generateModelFile(model)
  }

  const fileMap: FileMap = {
    models: modelFiles,
    'client.ts': generateClientFile(models),
    'index.ts': generateIndexFile(models, enums),
  }

  if (enums.length > 0) {
    fileMap['enums.ts'] = generateEnumsFile(enums)
  }

  await fs.rm(outputDir, { recursive: true, force: true })
  await fs.mkdir(outputDir, { recursive: true })
  await writeFileMap(outputDir, fileMap)
}

function generateEnumsFile(enums: readonly DMMF.DatamodelEnum[]): string {
  return (
    enums
      .map((e) => {
        const values = e.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
        return `export enum ${e.name} {\n${values}\n}`
      })
      .join('\n\n') + '\n'
  )
}

function generateIndexFile(
  models: readonly DMMF.Model[],
  enums: readonly DMMF.DatamodelEnum[],
): string {
  const lines = [
    `export { RestClient } from './client'`,
    `export type { RestClientOptions } from './client'`,
  ]
  if (enums.length > 0) {
    lines.push(`export { ${enums.map((e) => e.name).join(', ')} } from './enums'`)
  }
  for (const model of models) {
    lines.push(
      `export type { ${model.name}, ${model.name}WhereUniqueInput, ${model.name}CreateInput, ${model.name}UpdateInput } from './models/${model.name}'`,
    )
  }
  return lines.join('\n') + '\n'
}

async function writeFileMap(outputDir: string, fileMap: FileMap): Promise<void> {
  await Promise.all(
    Object.entries(fileMap).map(async ([name, content]) => {
      const dest = path.join(outputDir, name)
      if (typeof content === 'string') {
        await fs.mkdir(path.dirname(dest), { recursive: true })
        await fs.writeFile(dest, content)
      } else {
        await fs.mkdir(dest, { recursive: true })
        await writeFileMap(dest, content)
      }
    }),
  )
}
```

---

### `packages/rest-client-generator/src/generator.ts`

```typescript
import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateClient } from './generate-client'

export const RestClientGenerator: Generator = {
  name: 'rest-client-generator',

  getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      prettyName: 'Prisma REST Client Generator',
      defaultOutput: 'node_modules/.prisma/rest-client',
      requiresEngines: [],
    })
  },

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = options.generator.output?.value ?? 'rest-client'
    await generateClient(options.dmmf, outputDir)
  },
}
```

---

### `packages/rest-client-generator/src/index.ts`

The entry point both exports the generator object (for programmatic/test use) and wires it into the JSON-RPC protocol so the bundle can be spawned as a generator binary by the Prisma CLI.

```typescript
import { generatorHandler } from '@prisma/generator-helper'

import { RestClientGenerator } from './generator'

export { RestClientGenerator }

generatorHandler({
  onManifest(config) {
    return RestClientGenerator.getManifest(config)
  },
  onGenerate(options) {
    return RestClientGenerator.generate(options)
  },
})
```

> `generatorHandler` (`packages/generator-helper/src/generatorHandler.ts`) reads newline-delimited JSON from `process.stdin` and writes JSON-RPC responses to `process.stderr`. The call runs at module-load time; because `dist/index.js` is the spawned binary entry point, that is always correct.

---

## Files to Modify

### 1. `tsconfig.build.bundle.json` — add path alias

Add one entry after line 42 (the `"@prisma/ts-builders"` entry, currently the last one):

```diff
-      "@prisma/ts-builders": ["./packages/ts-builders/src"]
+      "@prisma/ts-builders": ["./packages/ts-builders/src"],
+      "@prisma/rest-client-generator": ["./packages/rest-client-generator/src"]
```

### 2. `.github/workflows/test-template.yml` — register in CI

Find the `others` job and add a test step for the new package (after the last `sqlcommenter-*` step):

```diff
+      - run: pnpm run test
+        name: 'rest-client-generator'
+        working-directory: packages/rest-client-generator
```

---

## Generated Output Structure

For a schema with `User` and `Post` models and a `Role` enum, the generator writes:

```
{outputDir}/
├── models/
│   ├── User.ts        — User, UserWhereUniqueInput, UserCreateInput, UserUpdateInput
│   └── Post.ts        — Post, PostWhereUniqueInput, PostCreateInput, PostUpdateInput
├── enums.ts           — export enum Role { ... }
├── client.ts          — RestClientOptions + RestClient class
└── index.ts           — re-exports everything
```

---

## Edge Cases

| Scenario | Handling |
|---|---|
| `kind === 'object'` (relation) | Excluded by `isSerializable()` — not flat JSON |
| `kind === 'unsupported'` | Excluded by `isSerializable()` — no TS equivalent |
| `kind === 'enum'` | Type is the enum name; emitted verbatim (enum defined in `enums.ts`) |
| `isId: true` | In `WhereUniqueInput` only; excluded from Create/UpdateInput |
| `isReadOnly: true` | Excluded from Create/UpdateInput (covers `@updatedAt`) |
| `hasDefaultValue: true` | Optional in CreateInput |
| `isList: true` | Type becomes `T[]` |
| `isRequired: false` | Gets `?` in base interface |
| `enums.length === 0` | `enums.ts` not written; no enum export in `index.ts` |
| `models.length === 0` | Empty `RestClient` class is emitted; no model accessors |

---

## Verification

1. **Build**  
   ```
   pnpm --filter @prisma/rest-client-generator build
   ```
   Expect `dist/index.js`, `dist/index.mjs`, `dist/index.d.ts`, `dist/index.d.mts`.

2. **Type-check**  
   ```
   pnpm tsc --noEmit -p tsconfig.build.bundle.json
   ```
   The new path alias ensures `@prisma/rest-client-generator` resolves in cross-package type checks.

3. **Smoke test** — create `test.prisma`:
   ```prisma
   generator restClient {
     provider = "node ./packages/rest-client-generator/dist/index.js"
     output   = "./rest-client-out"
   }
   datasource db {
     provider = "postgresql"
     url      = env("DATABASE_URL")
   }
   model User {
     id    Int    @id @default(autoincrement())
     name  String
     email String @unique
   }
   ```
   Run `prisma generate --schema test.prisma`. Verify `rest-client-out/models/User.ts`, `rest-client-out/client.ts`, `rest-client-out/index.ts` are generated with correct interfaces and methods.

4. **Unit tests** (optional but recommended)  
   Add `packages/rest-client-generator/src/prisma-type-to-ts.test.ts` with fixtures using synthetic `DMMF.Model` objects to test `generateModelFile` output. Run with:
   ```
   pnpm --filter @prisma/rest-client-generator test
   ```

