### 3.2 Datamodel
Contains the Prisma schema information:

```typescript
export type Datamodel = {
  models: Model[]
  enums: DatamodelEnum[]
  types: Model[]           // Composite types
  indexes: Index[]
}

export type Model = {
  name: string
  dbName: string | null
  schema: string | null
  fields: Field[]
  uniqueFields: string[][]
  uniqueIndexes: uniqueIndex[]
  documentation?: string
  primaryKey: PrimaryKey | null
  isGenerated?: boolean
}

export type Field = {
  kind: FieldKind           // 'scalar' | 'object' | 'enum' | 'unsupported'
  name: string
  isRequired: boolean
  isList: boolean
  isUnique: boolean
  isId: boolean
  isReadOnly: boolean
  isGenerated?: boolean
  isUpdatedAt?: boolean
  type: string              // 'Int', 'String', 'DateTime', '$ModelName', etc.
  nativeType?: [string, string[]] | null  // e.g., ['VarChar', ['191']]
  dbName?: string | null
  hasDefaultValue: boolean
  default?: FieldDefault | FieldDefaultScalar | FieldDefaultScalar[]
  relationFromFields?: string[]
  relationToFields?: string[]
  relationOnDelete?: string
  relationOnUpdate?: string
  relationName?: string
  documentation?: string
}

export type DatamodelEnum = {
  name: string
  values: EnumValue[]
  dbName?: string | null
  documentation?: string
}

export type EnumValue = {
  name: string
  dbName: string | null
}

