## 6. Writing Files to Output Directory

### 6.1 FileMap Structure
**File**: `packages/client-generator-ts/src/generateClient.ts`

```typescript
export interface FileMap {
  [name: string]: string | Buffer | FileMap
}

// Example structure:
const fileMap = {
  'client.ts': 'export class Prisma...',
  'enums.ts': 'export enum Status...',
  'models': {
    'user.ts': 'export type User...',
    'post.ts': 'export type Post...',
  },
  'internal': {
    'prismaNamespace.ts': '...',
    'class.ts': '...',
  }
}
```

### 6.2 Writing Files
```typescript
async function generateClient(options: GenerateClientOptions): Promise<void> {
  const { fileMap } = buildClient(options)

  await deleteOutputDir(outputDir)
  await ensureDir(outputDir)

  await writeFileMap(outputDir, fileMap)
}

function writeFileMap(outputDir: string, fileMap: FileMap) {
  return Promise.all(
    Object.entries(fileMap).map(async ([fileName, content]) => {
      const absolutePath = path.join(outputDir, fileName)
      await fs.rm(absolutePath, { recursive: true, force: true })
      if (typeof content === 'string' || Buffer.isBuffer(content)) {
        // Write file
        await fs.writeFile(absolutePath, content)
      } else {
        // Create subdirectory and recurse
        await fs.mkdir(absolutePath)
        await writeFileMap(absolutePath, content)
      }
    })
  )
}
```

**Key points**:
- Delete existing files first
- FileMap is a nested object where leaf values are strings or Buffers
- Directories are represented as nested objects
- Use `fs.writeFile` for content

