## 8. Practical Generator Flow

### 8.1 Minimal Generator Implementation

**Entry point** (generators are started as Node processes):
```typescript
import { generatorHandler } from '@prisma/generator-helper'
import { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

class MyGenerator implements Generator {
  readonly name = 'my-generator'

  async getManifest(config: GeneratorConfig): Promise<GeneratorManifest> {
    return {
      defaultOutput: './generated',
      prettyName: 'My Generator',
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const { dmmf, datasources, generator } = options
    const outputDir = parseEnvValue(generator.output!)

    // Access data:
    // - dmmf.datamodel.models: All models
    // - dmmf.datamodel.enums: All enums
    // - dmmf.datamodel.types: Composite types
    // - dmmf.schema.inputObjectTypes: Input type definitions
    // - dmmf.schema.outputObjectTypes: Output type definitions
    // - dmmf.mappings: Available operations per model

    // Build file map
    const fileMap = {}
    for (const model of dmmf.datamodel.models) {
      fileMap[`${model.name}.ts`] = generateModelFile(model)
    }

    // Write files
    await fs.mkdir(outputDir, { recursive: true })
    for (const [filename, content] of Object.entries(fileMap)) {
      await fs.writeFile(
        path.join(outputDir, filename),
        content
      )
    }
  }
}

generatorHandler({
  onManifest: (config) => new MyGenerator().getManifest(config),
  onGenerate: (options) => new MyGenerator().generate(options),
})
```

### 8.2 Building Code from DMMF

```typescript
function generateModelFile(model: DMMF.Model): string {
  const writer = new Writer()

  writer.writeLine(`export interface ${model.name} {`)
  writer.withIndent(() => {
    for (const field of model.fields) {
      const optional = field.isRequired ? '' : '?'
      const isArray = field.isList ? '[]' : ''
      writer.writeLine(`${field.name}${optional}: ${field.type}${isArray}`)
    }
  })
  writer.writeLine('}')

  return writer.toString()
}
```

---

## 9. Access Patterns

### 9.1 Data Available to Generators

```typescript
options: GeneratorOptions = {
  // Generator configuration
  generator: {
    name: 'my-generator',
    output: { fromEnvVar: null, value: './generated' },
    provider: { fromEnvVar: null, value: 'my-generator' },
    config: { /* custom config from schema */ },
    sourceFilePath: '/path/to/schema.prisma',
  },

  // Other active generators
  otherGenerators: [ /* ... */ ],

  // Schema information
  dmmf: {
    datamodel: {
      models: [ /* all models */ ],
      enums: [ /* all enums */ ],
      types: [ /* composite types */ ],
      indexes: [ /* all indexes */ ],
    },
    schema: {
      inputObjectTypes: { prisma: [ /* ... */ ], model: [ /* ... */ ] },
      outputObjectTypes: { prisma: [ /* ... */ ], model: [ /* ... */ ] },
      enumTypes: { /* ... */ },
    },
    mappings: {
      modelOperations: [ /* operation names per model */ ],
      otherOperations: { read: [ /* ... */ ], write: [ /* ... */ ] },
    },
  },

  // Database configuration
  datasources: [ /* database connections */ ],

  // Raw schema text
  datamodel: 'model User { ... }',

  // Schema file path
  schemaPath: '/path/to/schema.prisma',

  // Version info
  version: 'abc123hash',

  // Optional
  binaryPaths: { /* ... */ },
  typedSql: [ /* ... */ ],
}
```

### 9.2 Common Access Patterns

```typescript
// Get all models
const models = options.dmmf.datamodel.models

// Get specific model fields
const model = models.find(m => m.name === 'User')
const idField = model.fields.find(f => f.isId)

// Get enums
const enums = options.dmmf.datamodel.enums

// Get composite types (shared types)
const compositeTypes = options.dmmf.datamodel.types

// Get operations available for a model
