### `packages/rest-client-generator/src/generate-client.ts`

Main orchestrator: reads `dmmf.datamodel`, calls the per-model and client file generators, and writes the `FileMap` to disk. The `writeFileMap` helper is adapted from `packages/client-generator-ts/src/generateClient.ts` with an added `mkdir` for intermediate directories (needed because model files live in a `models/` subdirectory).

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { generateClientFile } from './client-file-generator'
import { generateModelFile } from './model-file-generator'

interface FileMap {
  [name: string]: string | FileMap
}

export async function generateClient(dmmf: DMMF.Document, outputDir: string): Promise<void> {
  const { models, enums } = dmmf.datamodel

  const modelFiles: FileMap = {}
  for (const model of models) {
    modelFiles[`${model.name}.ts`] = generateModelFile(model)
  }

  const fileMap: FileMap = {
    models: modelFiles,
    'client.ts': generateClientFile(models),
    'index.ts': generateIndexFile(models, enums),
  }

  if (enums.length > 0) {
    fileMap['enums.ts'] = generateEnumsFile(enums)
  }

  await fs.rm(outputDir, { recursive: true, force: true })
  await fs.mkdir(outputDir, { recursive: true })
  await writeFileMap(outputDir, fileMap)
}

function generateEnumsFile(enums: readonly DMMF.DatamodelEnum[]): string {
  return (
    enums
      .map((e) => {
        const values = e.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
        return `export enum ${e.name} {\n${values}\n}`
      })
      .join('\n\n') + '\n'
  )
}

function generateIndexFile(
  models: readonly DMMF.Model[],
  enums: readonly DMMF.DatamodelEnum[],
): string {
  const lines = [
    `export { RestClient } from './client'`,
    `export type { RestClientOptions } from './client'`,
  ]
  if (enums.length > 0) {
    lines.push(`export { ${enums.map((e) => e.name).join(', ')} } from './enums'`)
  }
  for (const model of models) {
    lines.push(
      `export type { ${model.name}, ${model.name}WhereUniqueInput, ${model.name}CreateInput, ${model.name}UpdateInput } from './models/${model.name}'`,
    )
  }
  return lines.join('\n') + '\n'
}

async function writeFileMap(outputDir: string, fileMap: FileMap): Promise<void> {
  await Promise.all(
    Object.entries(fileMap).map(async ([name, content]) => {
      const dest = path.join(outputDir, name)
      if (typeof content === 'string') {
        await fs.mkdir(path.dirname(dest), { recursive: true })
        await fs.writeFile(dest, content)
      } else {
        await fs.mkdir(dest, { recursive: true })
        await writeFileMap(dest, content)
      }
    }),
  )
}
