import type * as DMMF from '@prisma/dmmf'

/**
 * Generates the content of `client.ts`, which exports `RestClientOptions`
 * and the `RestClient` class with typed CRUD accessors for every model.
 */
export function generateClientFile(models: readonly DMMF.Model[]): string {
  const imports = models
    .map(
      (m) =>
        `import type { ${m.name}, ${m.name}WhereUniqueInput, ${m.name}CreateInput, ${m.name}UpdateInput } from './models/${m.name}'`,
    )
    .join('\n')

  const modelAccessors = models.map(generateModelAccessor).join('\n\n')

  return `${imports}

export interface RestClientOptions {
  baseUrl: string
  headers?: Record<string, string>
}

export class RestClient {
  #baseUrl: string
  #headers: Record<string, string>

  constructor(options: RestClientOptions) {
    this.#baseUrl = options.baseUrl.replace(/\\/$/, '')
    this.#headers = options.headers ?? {}
  }

${modelAccessors}

  #fetch<T>(path: string, init?: RequestInit): Promise<T> {
    return fetch(\`\${this.#baseUrl}\${path}\`, {
      ...init,
      headers: { 'Content-Type': 'application/json', ...this.#headers, ...init?.headers },
    }).then((res) => {
      if (!res.ok) {
        return res.text().then((body) => {
          throw new Error(\`HTTP \${res.status}: \${body}\`)
        })
      }
      return res.json() as Promise<T>
    })
  }
}
`
}

function accessorName(modelName: string): string {
  return modelName.charAt(0).toLowerCase() + modelName.slice(1)
}

function generateModelAccessor(model: DMMF.Model): string {
  const acc = accessorName(model.name)
  const M = model.name
  return `  readonly ${acc} = {
    findMany: (params?: { skip?: number; take?: number }): Promise<${M}[]> => {
      const qs = params ? \`?\${new URLSearchParams(params as Record<string, string>)}\` : ''
      return this.#fetch<${M}[]>(\`/${acc}\${qs}\`)
    },
    findUnique: (where: ${M}WhereUniqueInput): Promise<${M} | null> =>
      this.#fetch<${M} | null>(\`/${acc}/\${encodeURIComponent(JSON.stringify(where))}\`),
    create: (data: ${M}CreateInput): Promise<${M}> =>
      this.#fetch<${M}>(\`/${acc}\`, { method: 'POST', body: JSON.stringify(data) }),
    update: (where: ${M}WhereUniqueInput, data: ${M}UpdateInput): Promise<${M}> =>
      this.#fetch<${M}>(\`/${acc}/\${encodeURIComponent(JSON.stringify(where))}\`, {
        method: 'PATCH',
        body: JSON.stringify(data),
      }),
    delete: (where: ${M}WhereUniqueInput): Promise<${M}> =>
      this.#fetch<${M}>(\`/${acc}/\${encodeURIComponent(JSON.stringify(where))}\`, { method: 'DELETE' }),
  }`
}

