import type { User, UserWhereUniqueInput, UserCreateInput, UserUpdateInput } from './models/User'
import type { Post, PostWhereUniqueInput, PostCreateInput, PostUpdateInput } from './models/Post'

export interface RestClientOptions {
  baseUrl: string
  headers?: Record<string, string>
}

export class RestClient {
  #baseUrl: string
  #headers: Record<string, string>

  constructor(options: RestClientOptions) {
    this.#baseUrl = options.baseUrl.replace(/\/$/, '')
    this.#headers = options.headers ?? {}
  }

  readonly user = {
    findMany: (params?: { skip?: number; take?: number }): Promise<User[]> => {
      const qs = params ? `?${new URLSearchParams(params as Record<string, string>)}` : ''
      return this.#fetch<User[]>(`/user${qs}`)
    },
    findUnique: (where: UserWhereUniqueInput): Promise<User | null> =>
      this.#fetch<User | null>(`/user/${encodeURIComponent(JSON.stringify(where))}`),
    create: (data: UserCreateInput): Promise<User> =>
      this.#fetch<User>(`/user`, { method: 'POST', body: JSON.stringify(data) }),
    update: (where: UserWhereUniqueInput, data: UserUpdateInput): Promise<User> =>
      this.#fetch<User>(`/user/${encodeURIComponent(JSON.stringify(where))}`, {
        method: 'PATCH',
        body: JSON.stringify(data),
      }),
    delete: (where: UserWhereUniqueInput): Promise<User> =>
      this.#fetch<User>(`/user/${encodeURIComponent(JSON.stringify(where))}`, { method: 'DELETE' }),
  }

  readonly post = {
    findMany: (params?: { skip?: number; take?: number }): Promise<Post[]> => {
      const qs = params ? `?${new URLSearchParams(params as Record<string, string>)}` : ''
      return this.#fetch<Post[]>(`/post${qs}`)
    },
    findUnique: (where: PostWhereUniqueInput): Promise<Post | null> =>
      this.#fetch<Post | null>(`/post/${encodeURIComponent(JSON.stringify(where))}`),
    create: (data: PostCreateInput): Promise<Post> =>
      this.#fetch<Post>(`/post`, { method: 'POST', body: JSON.stringify(data) }),
    update: (where: PostWhereUniqueInput, data: PostUpdateInput): Promise<Post> =>
      this.#fetch<Post>(`/post/${encodeURIComponent(JSON.stringify(where))}`, {
        method: 'PATCH',
        body: JSON.stringify(data),
      }),
    delete: (where: PostWhereUniqueInput): Promise<Post> =>
      this.#fetch<Post>(`/post/${encodeURIComponent(JSON.stringify(where))}`, { method: 'DELETE' }),
  }

  #fetch<T>(path: string, init?: RequestInit): Promise<T> {
    return fetch(`${this.#baseUrl}${path}`, {
      ...init,
      headers: { 'Content-Type': 'application/json', ...this.#headers, ...init?.headers },
    }).then((res) => {
      if (!res.ok) {
        return res.text().then((body) => {
          throw new Error(`HTTP ${res.status}: ${body}`)
        })
      }
      return res.json() as Promise<T>
    })
  }
}

